686	func Bootstrap(ctx context.Context, cfg Config) (Result, error) {
687		if cfg.Force {
688			return Result{}, errors.New("bootstrap does not support --force")
689		}
690		if cfg.Prune {
691			return Result{}, errors.New("bootstrap does not support --prune")
692		}
693		if cfg.DryRun {
694			return Result{}, errors.New("bootstrap does not support dry-run; use plan or sync")
695		}
696	
697		s, err := newSession(ctx, cfg, true)
698		if err != nil {
699			return Result{}, err
700		}
701	
702		desiredRefs, _, err := planner.BuildDesiredRefs(s.sourceRefMap, planConfig(cfg))
703		if err != nil {
704			return Result{}, fmt.Errorf("build desired refs: %w", err)
705		}
706		if len(desiredRefs) == 0 {
707			return Result{}, errors.New("no source refs matched")
708		}
