363	// newSession performs the shared setup: protocol validation, mapping validation,
364	// connection creation, and ref discovery.
365	func newSession(ctx context.Context, cfg Config, needTarget bool) (*syncSession, error) {
366		mode, err := validation.NormalizeProtocolMode(cfg.ProtocolMode)
367		if err != nil {
368			return nil, fmt.Errorf("normalize protocol mode: %w", err)
369		}
370		cfg.ProtocolMode = mode
371		switch cfg.Mode {
372		case "", modeSync:
373			cfg.Mode = modeSync
374		case modeReplicate:
375		default:
376			return nil, fmt.Errorf("unsupported operation mode %q", cfg.Mode)
377		}
378		if _, err := validation.ValidateMappings(cfg.Mappings); err != nil {
379			return nil, fmt.Errorf("validate mappings: %w", err)
380		}
381		if cfg.Mode == modeReplicate && cfg.Force {
382			return nil, errors.New("replicate does not support --force; use sync instead")
383		}
384	
385		s := &syncSession{
386			cfg:             cfg,
387			stats:           newStats(cfg.ShowStats),
388			measurementDone: startMeasurement(cfg.MeasureMemory),
389		}
390		if cfg.Verbose {
391			s.logger = slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{
392				Level: slog.LevelInfo,
393			}))
394		}
395	
396		s.sourceConn, err = newConn(cfg.Source, "source", s.stats, cfg.HTTPClient)
397		if err != nil {
398			return nil, fmt.Errorf("create source transport: %w", err)
399		}
400	
401		refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
402		sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, s.sourceConn, cfg.ProtocolMode, refPrefixes)
403		if err != nil {
404			return nil, fmt.Errorf("list source refs: %w", err)
405		}
406		sourceService.Verbose = cfg.Verbose
407		s.sourceService = sourceService
408		s.sourceRefMap = gitproto.RefHashMap(sourceRefs)
409	
410		if needTarget {
411			targetConn, err := newConn(cfg.Target, "target", s.stats, cfg.HTTPClient)
412			if err != nil {
413				return nil, fmt.Errorf("create target transport: %w", err)
414			}
415			targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackService)
416			if err != nil {
417				return nil, fmt.Errorf("list target refs: %w", err)
418			}
419			targetRefSlice, err := gitproto.AdvRefsToSlice(targetAdv)
420			if err != nil {
421				return nil, fmt.Errorf("decode target refs: %w", err)
422			}
423			targetRefMap := gitproto.RefHashMap(targetRefSlice)
424			targetFeatures := gitproto.TargetFeaturesFromAdvRefs(targetAdv)
425			s.target = &targetSession{
426				conn:     targetConn,
427				adv:      targetAdv,
428				refMap:   targetRefMap,
429				features: targetFeatures,
430				policy: planner.RelayTargetPolicy{
431					CapabilitiesKnown: targetFeatures.Known,
432					NoThin:            targetFeatures.NoThin,
433				},
434				pusher: gitproto.NewPusher(targetConn, targetAdv, cfg.Verbose),
435			}
436		}
437	
438		return s, nil
439	}
